            if p(e['input'])!=e['output']:
                fails+=1
        except Exception as ex:
            return ('RUNERR',str(ex))
    vf=0
    for e in val:
        try:
            if p(e['input'])!=e['output']: vf+=1
        except Exception as ex:
            return ('VALERR',str(ex))
    return (fails,vf,len(src))

cands={
'A_orig':"p=lambda g:[[[y,x][u<any(b)]for x,y,u in zip([0]+a,a,[0]+b)]for a,b in zip(g,g[1:]+g)]",
'B_a1':"p=lambda g:[[0]+[[z,y][v<any(b)]for y,z,v in zip(a,a[1:],b)]for a,b in zip(g,g[1:]+g)]",
'B_gt':"p=lambda g:[[0]+[[z,y][any(b)>v]for y,z,v in zip(a,a[1:],b)]for a,b in zip(g,g[1:]+g)]",
'B_max':"p=lambda g:[[0]+[[z,y][v<max(b)]for y,z,v in zip(a,a[1:],b)]for a,b in zip(g,g[1:]+g)]",
'B_yz':"p=lambda g:[[0]+[[y,z][v>=any(b)]for y,z,v in zip(a,a[1:],b)]for a,b in zip(g,g[1:]+g)]",
}
for k,s in cands.items():
    print(k,test(s),len(s))

