import json,os,sys
sys.path.insert(0,os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
from gen import validate
d=json.load(open('data.json'))['arc-gen']
v=validate()
val=[e for s in('train','test')for e in v[s]]
ALL=[(e['input'],e['output'])for e in d]+[(e['input'],e['output'])for e in val]

def ok(src):
    ns={}
    try:
        exec(src,ns);p=ns['p']
    except Exception:return None
    try:
        for I,O in ALL:
            if p(I)!=O:return False
    except Exception:return False
    return True

# building blocks
gates=['any(b)','max(b)']
# 3-var flat zip form: (x,y,u)=(a[c-1],a[c],b[c-1])
sels3=[]
for G in gates:
    sels3+= [f'[y,x][u<{G}]',f'[x,y][u>={G}]',f'[y,x][{G}>u]',f'x if u<{G}else y']
zip3=['[0]+a,a,[0]+b']
# 2-zip+prefix form: (z,y,v)=(a[d+1],a[d],b[d]) via zip(a,a[1:],b) ... but that's 3 too
# form B: prefix [0]+ , zip(a,a[1:],b) -> y,z,v = a[d],a[d+1],b[d]
selsB=[]
for G in gates:
    selsB+=[f'[z,y][v<{G}]',f'[y,z][v>={G}]',f'[z,y][{G}>v]',f'y if v<{G}else z']

cands={}
for z in zip3:
    for s in sels3:
        cands[f'p=lambda g:[[{s}for x,y,u in zip({z})]for a,b in zip(g,g[1:]+g)]']=1
for s in selsB:
    cands[f'p=lambda g:[[0]+[{s}for y,z,v in zip(a,a[1:],b)]for a,b in zip(g,g[1:]+g)]']=1
    cands[f'p=lambda g:[[0,*[{s}for y,z,v in zip(a,a[1:],b)]]for a,b in zip(g,g[1:]+g)]']=1

# arithmetic index forms on padded a: out[c]=([0]+a)[c+(cond)]
for G in gates:
    cands[f'p=lambda g:[[([0]+a)[i+(v>={G})]for i,v in enumerate([0]+b)][:len(a)]for a,b in zip(g,g[1:]+g)]']=1

res=[]
for s in cands:
    r=ok(s)
    if r:res.append((len(s),s))
res.sort()
print('PASSING candidates (sorted by length):')
for L,s in res[:20]:
    print(L,s)
print('total passing:',len(res),'best:',res[0][0] if res else None)

